var W=0,H=0,DPR=1,WORLD_W=0,WORLD_H=0,CAMX=0,CAMY=0,S=null,last=0,saveAt=0,boardBusy=false,audio=null,pendingClass=null,pendingDlcClass=null,selectedMap='chaos',mapTipOpen=false,targetEvo=null,equipViewClass='paladin',equipFilter='all',equipBulk=false,equipBulkPick=new Set(),layoutEdit=false,layoutDraft=null,dragLayout=null,layoutCache=null,fxQuality='low',dmgNumberMode='topAll',viewPrefs={portraitView:80,landscapeView:78},settingsReady=false,SETTINGS_VERSION='20260618-view-fx-dmg-v2',control={auto:true,style:0,x:0,y:0,active:false,target:null};function ensureSettingsDefaults(){if(settingsReady)return;settingsReady=true;try{if(localStorage.getItem('arcaneSettingsVersion')!==SETTINGS_VERSION){localStorage.setItem('portraitView','80');localStorage.setItem('landscapeView','78');localStorage.setItem('fxQuality','low');localStorage.setItem('dmgNumberMode','topAll');localStorage.setItem('arcaneSettingsVersion',SETTINGS_VERSION)}}catch(_){}}function viewDefault(id){return id==='landscapeView'?78:80}function viewScale(){ensureSettingsDefaults();let id=innerWidth>innerHeight?'landscapeView':'portraitView';return viewSetting(id,viewDefault(id))/100}function resize(){DPR=devicePixelRatio||1;let scale=viewScale(),cw=canvas.clientWidth,ch=canvas.clientHeight;W=cw/scale;H=ch/scale;WORLD_W=Math.max(W*5,2800);WORLD_H=Math.max(H*5,5200);canvas.width=cw*DPR;canvas.height=ch*DPR;ctx.setTransform(DPR*scale,0,0,DPR*scale,0,0);updateCamera();applyLayout()}function updateCamera(){let p=S?.player;if(!p){CAMX=0;CAMY=0;return}CAMX=clamp(p.x-W/2,0,Math.max(0,WORLD_W-W));CAMY=clamp(p.y-H/2,0,Math.max(0,WORLD_H-H))}addEventListener('resize',resize);new ResizeObserver(resize).observe(document.body);
function initAudio(){if(audio)return;let C=window.AudioContext||window.webkitAudioContext;if(!C)return;let ctxA=new C(),master=ctxA.createGain(),music=ctxA.createGain(),fx=ctxA.createGain(),bgm=new Audio(BGM_SRC);master.gain.value=.55;music.gain.value=.36;fx.gain.value=.42;music.connect(master);fx.connect(master);master.connect(ctxA.destination);bgm.loop=true;bgm.volume=bgmVol();bgm.preload='auto';audio={ctx:ctxA,master,music,fx,bgm,menu:false,menuTimer:null,last:{},step:0,beat:null};startMusic()}
function tone(freq,dur,type='sine',vol=.12,dest='fx',when=0,endFreq=null){if(!audio)return;let c=audio.ctx,o=c.createOscillator(),g=c.createGain(),t=c.currentTime+when;o.type=type;o.frequency.setValueAtTime(freq,t);if(endFreq)o.frequency.exponentialRampToValueAtTime(endFreq,t+dur*.9);g.gain.setValueAtTime(.001,t);g.gain.linearRampToValueAtTime(vol,t+.015);g.gain.exponentialRampToValueAtTime(.001,t+dur);o.connect(g);g.connect(audio[dest]);o.start(t);o.stop(t+dur+.04)}
function noise(dur,vol=.1,when=0,filter='highpass',freq=900){if(!audio)return;let c=audio.ctx,b=c.createBuffer(1,c.sampleRate*dur,c.sampleRate),d=b.getChannelData(0);for(let i=0;i<d.length;i++)d[i]=(Math.random()*2-1)*(1-i/d.length*.6);let s=c.createBufferSource(),g=c.createGain(),f=c.createBiquadFilter(),t=c.currentTime+when;f.type=filter;f.frequency.value=freq;g.gain.setValueAtTime(vol,t);g.gain.exponentialRampToValueAtTime(.001,t+dur);s.buffer=b;s.connect(f);f.connect(g);g.connect(audio.fx);s.start(t)}
function arp(list,dur,type='sine',vol=.05,gap=.045){list.forEach((n,i)=>tone(n,dur,type,vol,'fx',i*gap))}
function sfx(k){if(!audio)return;let c=audio.ctx,now=c.currentTime;if(audio.last[k]&&now-audio.last[k]<.08)return;audio.last[k]=now;if(k==='click'){tone(420,.07,'triangle',.07,'fx',0,720);tone(980,.09,'sine',.04,'fx',.025);noise(.055,.03,0,'highpass',2200)}else if(k==='magic'){arp([520,660,880],.12,'triangle',.055);tone(260,.22,'sine',.045,'fx',0,390)}else if(k==='fire'){noise(.22,.12,0,'lowpass',1400);tone(120,.18,'sawtooth',.09,'fx',0,70);tone(520,.16,'triangle',.045,'fx',.03,760)}else if(k==='ice'){arp([740,988,1318],.16,'sine',.045,.03);noise(.12,.045,.02,'highpass',2600)}else if(k==='throw'){noise(.1,.09,0,'bandpass',1200);tone(190,.12,'sawtooth',.055,'fx',0,130)}else if(k==='lance'){tone(520,.12,'triangle',.08,'fx',0,980);tone(1040,.18,'sine',.05,'fx',.03);noise(.08,.045,.02,'highpass',1800)}else if(k==='beam'){tone(220,.28,'sawtooth',.055,'fx',0,330);tone(880,.26,'triangle',.045,'fx',0,660);noise(.18,.045,.04,'bandpass',1700)}else if(k==='slash'){noise(.12,.075,0,'highpass',2100);tone(900,.1,'triangle',.07,'fx',0,520)}else if(k==='fall'){tone(360,.22,'sawtooth',.07,'fx',0,80);noise(.18,.085,.06,'lowpass',700)}else if(k==='boom'){noise(.28,.18,0,'lowpass',900);tone(82,.26,'sine',.13,'fx',0,48);tone(164,.18,'triangle',.055,'fx',.04,96)}else if(k==='chain'){for(let i=0;i<4;i++)tone(900+Math.random()*500,.045,'square',.055,'fx',i*.035,500+Math.random()*400);noise(.08,.05,0,'highpass',3000)}else if(k==='rift'){tone(140,.34,'sawtooth',.07,'fx',0,55);tone(70,.38,'sine',.09,'fx',.04,42);noise(.28,.06,.04,'lowpass',500)}else if(k==='poison'){noise(.22,.07,0,'bandpass',520);tone(180,.25,'sawtooth',.045,'fx',0,120)}else if(k==='holy'){arp([392,587,784,1174],.18,'triangle',.055,.035);tone(196,.28,'sine',.045,'fx',0,294)}}
function bgmVol(){let v=Number($('bgmVolume')?.value??42);return Math.max(0,Math.min(1,v/100))}
function fxScale(){return fxQuality==='off'?0:fxQuality==='low'?.25:fxQuality==='medium'?.55:1}
function fxOff(){return fxScale()<=0}
function fxSpriteOnly(){return fxQuality==='low'}
function shouldDrawFx(i=0){let q=fxScale();return q>0&&(q>=1||i%Math.max(1,Math.round(1/q))===0)}
function viewSetting(id,def,fromInput=false){let raw=fromInput?$(id)?.value:null;if(raw==null)try{raw=localStorage.getItem(id)}catch(_){}if(raw==null)raw=viewPrefs?.[id];let v=Number(raw??$(id)?.value??def);return Math.max(60,Math.min(120,v))}
function applyBgmVol(){let v=Math.round(bgmVol()*100);if(audio?.bgm)audio.bgm.volume=v/100;if($('bgmVolumeTxt'))$('bgmVolumeTxt').textContent=v+'%'}
function applyFxQuality(fromInput=false){let el=$('fxQuality'),txt=$('fxQualityTxt'),stored=null;if(!fromInput)try{stored=localStorage.getItem('fxQuality')}catch(_){}let v=(fromInput?el?.value:stored)||fxQuality||'low';if(!['off','low','medium','high'].includes(v))v='low';fxQuality=v;if(el)el.value=v;try{localStorage.setItem('fxQuality',v)}catch(_){}if(txt)txt.textContent={off:'关闭 · 只显示伤害',low:'低 · 省电',medium:'中 · 均衡',high:'高 · 全特效'}[v]}
function applyDmgNumberMode(fromInput=false){let el=$('dmgNumberMode'),txt=$('dmgNumberModeTxt'),stored=null;if(!fromInput)try{stored=localStorage.getItem('dmgNumberMode')}catch(_){}let v=(fromInput?el?.value:stored)||dmgNumberMode||'topAll',ok=['none','all','crit','normal','topAll','topNormal','topCrit'];if(!ok.includes(v))v='topAll';dmgNumberMode=v;if(el)el.value=v;try{localStorage.setItem('dmgNumberMode',v)}catch(_){}if(txt)txt.textContent={none:'不显示',all:'全部',crit:'暴击',normal:'普通',topAll:'前10全部',topNormal:'前10普通',topCrit:'前10暴击'}[v]}
function loadFxQuality(){applyFxQuality();applyDmgNumberMode()}
function applyViewSettings(fromInput=false){['portraitView','landscapeView'].forEach(id=>{let el=$(id),txt=$(id+'Txt'),v=viewSetting(id,viewDefault(id),fromInput);viewPrefs[id]=v;if(el)el.value=v;try{localStorage.setItem(id,v)}catch(_){}if(txt)txt.textContent=v<100?`远 · 显示更多 ${100-v}%`:v>100?`近 · 角色更大 +${v-100}%`:'标准'});resize()}
